import * as Notifications from "expo-notifications";
import client from "../api/client";

export async function registerForPushNotifications() {
  const { status: existingStatus } = await Notifications.getPermissionsAsync();
  let finalStatus = existingStatus;

  if (existingStatus !== "granted") {
    const { status } = await Notifications.requestPermissionsAsync();
    finalStatus = status;
  }

  if (finalStatus !== "granted") {
    return null;
  }

  const tokenData = await Notifications.getExpoPushTokenAsync();
  const token = tokenData.data;

  await client.post("/users/me/fcm-token", { token });

  return token;
}

export function configureNotificationHandler() {
  Notifications.setNotificationHandler({
    handleNotification: async () => ({
      shouldShowAlert: true,
      shouldPlaySound: true,
      shouldSetBadge: false,
    }),
  });
}

import { createSlice, createAsyncThunk } from "@reduxjs/toolkit";
import client from "../api/client";

export const fetchRewardsBalance = createAsyncThunk(
  "rewards/fetchBalance",
  async (_, { rejectWithValue }) => {
    try {
      const response = await client.get("/users/me/rewards");
      return response.data;
    } catch (err) {
      return rejectWithValue(err.response?.data || "Unknown error");
    }
  }
);

const rewardsSlice = createSlice({
  name: "rewards",
  initialState: {
    points: 0,
    loading: false,
    error: null,
  },
  reducers: {},
  extraReducers: (builder) => {
    builder
      .addCase(fetchRewardsBalance.pending, (state) => {
        state.loading = true;
        state.error = null;
      })
      .addCase(fetchRewardsBalance.fulfilled, (state, action) => {
        state.loading = false;
        state.points = action.payload.rewards_points;
      })
      .addCase(fetchRewardsBalance.rejected, (state, action) => {
        state.loading = false;
        state.error = action.payload;
      });
  },
});

export default rewardsSlice.reducer;

import { createSlice, createAsyncThunk } from "@reduxjs/toolkit";
import { fetchOrders, createOrder } from "../api/orders";

export const loadOrders = createAsyncThunk(
  "orders/loadAll",
  async (_, { rejectWithValue }) => {
    try {
      const response = await fetchOrders();
      return response.data;
    } catch (err) {
      return rejectWithValue(err.response?.data || "Unknown error");
    }
  }
);

export const submitOrder = createAsyncThunk(
  "orders/submit",
  async (orderPayload, { rejectWithValue }) => {
    try {
      const response = await createOrder(orderPayload);
      return response.data;
    } catch (err) {
      return rejectWithValue(err.response?.data || "Unknown error");
    }
  }
);

const ordersSlice = createSlice({
  name: "orders",
  initialState: {
    items: [],
    loading: false,
    error: null,
  },
  reducers: {},
  extraReducers: (builder) => {
    builder
      .addCase(loadOrders.pending, (state) => {
        state.loading = true;
      })
      .addCase(loadOrders.fulfilled, (state, action) => {
        state.loading = false;
        state.items = action.payload;
      })
      .addCase(loadOrders.rejected, (state, action) => {
        state.loading = false;
        state.error = action.payload;
      });
  },
});

export default ordersSlice.reducer;

import React, { useEffect } from "react";
import { View, Text, StyleSheet, ActivityIndicator } from "react-native";
import { useDispatch, useSelector } from "react-redux";
import { fetchRewardsBalance } from "../store/rewardsSlice";
import RewardsBadge from "../components/RewardsBadge/RewardsBadge";

export default function RewardsScreen() {
  const dispatch = useDispatch();
  const { points, loading, error } = useSelector((state) => state.rewards);

  useEffect(() => {
    dispatch(fetchRewardsBalance());
  }, [dispatch]);

  if (loading) return <ActivityIndicator style={styles.center} />;
  if (error) return <Text style={styles.error}>Failed to load rewards.</Text>;

  return (
    <View style={styles.container}>
      <Text style={styles.heading}>Your Rewards</Text>
      <RewardsBadge points={points} />
      <Text style={styles.subtext}>
        Earn 2x points every weekend. Points can be redeemed at checkout.
      </Text>
    </View>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1, padding: 24, backgroundColor: "#fff" },
  heading: { fontSize: 24, fontWeight: "700", marginBottom: 16 },
  subtext: { fontSize: 13, color: "#666", marginTop: 20 },
  center: { flex: 1, justifyContent: "center", alignItems: "center" },
  error: { color: "red", padding: 16 },
});

